import{_ as p,o,c as l,a5 as a}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0010：单相功率因数校正（power factor correction / PFC）电压环如何生成电流幅值","description":"","frontmatter":{"title":"教程 0010：单相功率因数校正（power factor correction / PFC）电压环如何生成电流幅值","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0010-single-phase-pfc-voltage-loop.html","status":"learning","visibility":"public","summary":"Imported from 0010-single-phase-pfc-voltage-loop.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0010-single-phase-pfc-voltage-loop.md","filePath":"content/power/lessons/0010-single-phase-pfc-voltage-loop.md","lastUpdated":null}'),i={name:"content/power/lessons/0010-single-phase-pfc-voltage-loop.md"};function t(r,e,c,n,s,d){return o(),l("div",null,[...e[0]||(e[0]=[a(`<h1 id="教程-0010-单相功率因数校正-power-factor-correction-pfc-电压环如何生成电流幅值" tabindex="-1">教程 0010：单相功率因数校正（power factor correction / PFC）电压环如何生成电流幅值 <a class="header-anchor" href="#教程-0010-单相功率因数校正-power-factor-correction-pfc-电压环如何生成电流幅值" aria-label="Permalink to &quot;教程 0010：单相功率因数校正（power factor correction / PFC）电压环如何生成电流幅值&quot;">​</a></h1><p>中文主讲。一个概念：母线电压误差如何变成电流参考幅值；一个仿真任务：观察负载阶跃后电压环如何抬高电导命令。这里仍不展开内层电流环和 PWM。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>电压环（voltage loop）是 PFC 控制里的慢速外环。它根据直流母线电压误差，决定输入电流参考的幅值。</p><p>本节用 电导命令（conductance command / G） 表示这个幅值。上一节已经讲过：</p><p>i_ref(t) = G * v_ac(t)</p><p>本节只回答一个问题：<code>G</code> 为什么会变大或变小。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）的 PFC 前级要维持稳定直流母线。负载功率突然增加时，母线电容放电，母线电压下降。电压环必须提高输入功率，让母线回到目标值。</p><ul><li><p>负载变大：母线下降，电压环提高电流幅值。</p></li><li><p>负载变小：母线上升，电压环降低电流幅值。</p></li><li><p>母线稳定：输入功率约等于负载功率加损耗。</p></li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>直流母线电容像水箱。负载是出水，PFC 输入功率是进水。水位低于目标时，电压环开大进水阀；水位高于目标时，电压环关小进水阀。</p><pre><code>Vbus_ref - Vbus
母线误差

PI 电压环
慢速外环

G 命令
电流幅值

i_ref = G * vac
给电流环跟踪

母线电压反馈
</code></pre><p>图 1：PFC 电压环只决定电流参考幅值；内层电流环和 PWM 后续再学。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>母线电压误差：</p><p>e_v[k] = Vbus_ref - Vbus[k]</p><p>比例积分控制器（proportional-integral controller / PI）输出电导命令：</p><p>G[k] = clamp(Kp * e_v[k] + integral[k], Gmin, Gmax) integral[k+1] = integral[k] + Ki * e_v[k] * Ts</p><p>输入功率近似为：</p><p>Pin[k] = G[k] * Vrms^2</p><p>母线能量平衡：</p><p>0.5 * Cbus * (Vbus[k+1]^2 - Vbus[k]^2) = (Pin[k] - Pload[k]) * Ts</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_pfc_voltage_loop.py</p><p>脚本会生成并自动打开图；如果无法自动打开，会打印完整路径。图中包含母线电压、电导命令、输入功率、负载功率和电流参考的均方根值（root mean square / RMS）。</p><pre><code>对比实验
python simulations\\python\\single_phase_pfc_voltage_loop.py --load-power-step 900 --output simulations\\results\\pfc_voltage_loop_900w.png --no-open
</code></pre><p>python simulations\\python\\single_phase_pfc_voltage_loop.py --load-power-step 1500 --output simulations\\results\\pfc_voltage_loop_1500w.png --no-open</p><p>比较负载阶跃越大时，母线下跌、电导命令和电流 RMS 参考如何变化。</p><p>观察顺序：</p><ul><li><p>看负载阶跃后母线电压是否先下降。</p></li><li><p>看电压环是否提高 <code>G</code>。</p></li><li><p>看输入功率 <code>Pin</code> 是否跟随上升。</p></li><li><p>看电流参考 RMS 是否随 <code>G</code> 增大。</p></li><li><p>看母线是否回到参考值附近。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 PFC 固件中，电压环通常比电流环慢。它输出的变量可能叫：</p><ul><li><p><code>i_amp_ref</code>：电流幅值参考。</p></li><li><p><code>p_cmd</code>：功率命令。</p></li><li><p><code>g_cmd</code>：电导命令。</p></li><li><p><code>i_ref_scale</code>：归一化电流参考比例。</p></li></ul><p>阅读代码时先找母线电压采样进入哪里，再找 PI 输出在哪里限幅，以及它在哪里与输入电压或单位正弦相乘。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**PFC 电压环直接控制 PWM。 **纠正：**电压环通常只给电流幅值，内层电流环才负责快速跟踪。</p></li><li><p>**误解：**电压环越快越好。 **纠正：**单相 PFC 母线有二倍工频纹波，电压环太快会把纹波调进电流参考。</p></li><li><p>**误解：**负载阶跃后母线不能下跌。 **纠正：**母线电容承担能量缓冲，短暂下跌正常，关键是恢复过程和保护边界。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释电压环（voltage loop）为什么是慢速外环。</p></li><li><p>能解释 <code>G</code> 增大为什么会提高输入功率。</p></li><li><p>能在图中指出母线电压、电导命令、输入功率、负载功率和电流参考 RMS。</p></li><li><p>能解释为什么需要 <code>Gmax</code> 限幅和抗积分饱和。</p></li><li><p>能基于仿真图准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>默认仿真中负载从多少 W 阶跃到多少 W？发生在多少 ms？</p></li><li><p>负载阶跃后，为什么 <code>G</code> 和电流参考 RMS 会升高？</p></li><li><p>如果电压环追踪二倍工频纹波，会对输入电流参考造成什么影响？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_pfc_voltage_loop.py</code> 看到负载从 600 W 到 1200 W 后，电压环提高 <code>G</code>，输入功率上升。公司 PFC 代码里电压环输出的是电流幅值、功率命令还是电导命令？</p></li><li><p>图中 <code>Gmax</code> 会限制最大输入功率。真实工程中 PFC 电压环输出限幅通常由哪些因素决定？</p></li><li><p>单相 PFC 母线上有二倍工频纹波。公司工程里电压环带宽如何避免追踪二倍频纹波？</p></li></ul><p>**下一步：**下一节再讲内层电流环如何让真实电感电流跟踪 <code>i_ref</code>，不要把外环、内环和 PWM 一次混在一起。</p><p>关联：<a href="./0009-single-phase-pfc-current-reference.html">上一节：单相 PFC 电流参考</a>；源稿：<code>concepts/power-electronics/single-phase-pfc-voltage-loop.md</code>。</p><pre><code>上一节：教程 0009：单相功率因数校正（power factor correction / PFC）电流参考
下一节：教程 0011：单相功率因数校正（power factor correction / PFC）内层电流环
</code></pre>`,50)])])}const u=p(i,[["render",t]]);export{_ as __pageData,u as default};
